import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { AuthService } from '../../core/services/auth.service';
import { EventItem, RsvpStatus } from '../../core/models';

/**
 * GatherUp public event detail. Shows capacity / confirmed / waitlist counts and
 * a login-gated RSVP / Cancel CTA. Anonymous users are sent to /login.
 * Loads live via ApiService.getEvent(id); RSVP/cancel call rsvp()/cancelRsvp()
 * and re-fetch to refresh counts and the caller's status.
 */
@Component({
  selector: 'app-event-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './event-detail.component.html',
  styleUrl: './event-detail.component.css',
})
export class EventDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly acting = signal(false);

  // Held as a single-element list so the `event` computed keeps working.
  readonly events = signal<EventItem[]>([]);

  readonly eventId = signal<string>('');
  readonly event = computed<EventItem | undefined>(() =>
    this.events().find((e) => e.id === this.eventId()) ?? this.events()[0],
  );

  readonly spotsLeft = computed(() => {
    const e = this.event();
    return e ? Math.max(0, e.capacity - (e.confirmedCount ?? 0)) : 0;
  });
  readonly isFull = computed(() => this.spotsLeft() === 0);

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
    private api: ApiService,
  ) {}

  ngOnInit(): void {
    this.eventId.set(this.route.snapshot.paramMap.get('id') ?? '');
    this.load();
  }

  /** Fetch the event with counts and (when authed) the caller's RSVP status. */
  private load(): void {
    const id = this.eventId();
    if (!id) return;
    this.loading.set(true);
    this.error.set(null);
    this.api.getEvent(id).subscribe({
      next: (event) => {
        // Backend returns `myRsvp: { status } | null`; normalise to myRsvpStatus.
        const myRsvp = (event as EventItem & { myRsvp?: { status: RsvpStatus } | null }).myRsvp;
        this.events.set([{ ...event, myRsvpStatus: myRsvp?.status ?? null }]);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load this event.');
        this.loading.set(false);
      },
    });
  }

  /** RSVP CTA. Anonymous users are redirected to login (login-gated). */
  onRsvp(): void {
    if (!this.auth.isLoggedIn()) {
      this.router.navigate(['/login']);
      return;
    }
    this.acting.set(true);
    this.api.rsvp(this.eventId()).subscribe({
      next: () => {
        this.acting.set(false);
        this.load();
      },
      error: () => {
        this.error.set('Could not RSVP. Please try again.');
        this.acting.set(false);
      },
    });
  }

  onCancel(): void {
    this.acting.set(true);
    this.api.cancelRsvp(this.eventId()).subscribe({
      next: () => {
        this.acting.set(false);
        this.load();
      },
      error: () => {
        this.error.set('Could not cancel your RSVP. Please try again.');
        this.acting.set(false);
      },
    });
  }

  statusBadge(status?: RsvpStatus | null): { cls: string; label: string } | null {
    switch (status) {
      case 'confirmed': return { cls: 'badge-ok', label: 'You\'re going' };
      case 'checkedIn': return { cls: 'badge-info', label: 'Checked in' };
      case 'waitlist': return { cls: 'badge-warn', label: 'On the waitlist' };
      default: return null;
    }
  }

  when(iso: string): string {
    return new Date(iso).toLocaleString(undefined, {
      weekday: 'long', month: 'long', day: 'numeric', hour: 'numeric', minute: '2-digit',
    });
  }
}
